import json
import uuid

assert 'long_df' in dir() and not long_df.empty, "⚠ Please run the data-loading cell first."

geo_long = long_df[long_df["latitude"].notna()].copy()

# Build one marker record per (well, gender) — a well with patrons
# of both genders produces two records, one per map.
def build_markers(gender):
    subset = geo_long[geo_long["gender"] == gender]
    # Aggregate patrons per well *within this gender*
    records = {}
    for _, row in subset.iterrows():
        uri = row["item"]
        if uri not in records:
            records[uri] = {
                "lat": float(row["latitude"]),
                "lon": float(row["longitude"]),
                "name": row["itemLabel"],
                "qid": row["qid"],
                "country": row["country"],
                "patrons": [],
            }
        records[uri]["patrons"].append(row["namedAfterLabel"])
    for r in records.values():
        r["patrons"] = sorted(set(r["patrons"]))
    return list(records.values())

female_markers = build_markers("female")
male_markers   = build_markers("male")

