### Step 3b — Female patrons, one layer per saint

Same data as the left map above, but now each saint gets her own
toggleable layer with a distinct colour — the colour swatch sits
directly in the layer-control label, so the panel itself acts as
the legend. This mirrors the
[Wikidata Query Service map view](https://w.wiki/AQ2F), which uses
the `?layer` variable to drive categorical colouring, and lets you
isolate individual dedications to see their geography on their own.


::: {.cell autorun='false'}
```{pyodide}
#| label: map-female-by-saint
#| autorun: false
import json
import uuid

assert 'long_df' in dir() and not long_df.empty, "⚠ Please run the data-loading cell first."

# A 24-colour categorical palette — D3's category20 extended. More
# saints than colours is handled by cycling, which is fine because
# the toggle makes adjacent colour collisions unimportant.
PALETTE = [
    "#1f77b4", "#ff7f0e", "#2ca02c", "#d62728", "#9467bd", "#8c564b",
    "#e377c2", "#17becf", "#bcbd22", "#7f7f7f", "#aec7e8", "#ffbb78",
    "#98df8a", "#ff9896", "#c5b0d5", "#c49c94", "#f7b6d2", "#9edae5",
    "#dbdb8d", "#c7c7c7", "#393b79", "#637939", "#8c6d31", "#843c39",
]

def build_per_saint_map(gender, container_id):
    """Prepare payload + HTML for one gendered per-saint map."""
    sub = long_df[(long_df["gender"] == gender) & long_df["latitude"].notna()].copy()

    # Order saints by descending well count so frequent saints get
    # stable, distinguishable palette slots.
    order = (sub.drop_duplicates(subset=["item", "namedAfterLabel"])
                .groupby("namedAfterLabel").size()
                .sort_values(ascending=False).index.tolist())
    saint_colour = {name: PALETTE[i % len(PALETTE)] for i, name in enumerate(order)}

    markers = [{
        "lat":    float(row["latitude"]),
        "lon":    float(row["longitude"]),
        "name":   row["itemLabel"],
        "qid":    row["qid"],
        "country": row["country"],
        "saint":  row["namedAfterLabel"],
        "colour": saint_colour[row["namedAfterLabel"]],
    } for _, row in sub.iterrows()]

    saints = [{"saint": s, "colour": saint_colour[s]} for s in order]

    if not markers:
        return None, None, 0
    all_lats = [m["lat"] for m in markers]
    all_lons = [m["lon"] for m in markers]
    centre = [sum(all_lats)/len(all_lats), sum(all_lons)/len(all_lons)]

    payload = json.dumps({"markers": markers, "saints": saints,
                          "centre": [float(centre[0]), float(centre[1])]})
    return payload, saints, len(markers)

female_payload, female_saints, female_n = build_per_saint_map("female", "")
print(f"  female: {female_n} markers across {len(female_saints)} saints")

map_id   = f"wells-female-saints-{uuid.uuid4().hex[:8]}"
data_var = f"__wellsFemaleSaints_{map_id.replace('-', '_')}"

html = f"""
<div id="{map_id}" style="height:620px;width:100%;border:1px solid #ddd;
     border-radius:4px"></div>
<link rel="stylesheet"
      href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
<link rel="stylesheet"
      href="https://unpkg.com/leaflet.fullscreen@3.0.2/Control.FullScreen.css" />
<script>window["{data_var}"] = {female_payload};</script>
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
<script>
(function() {{
    const mapId = "{map_id}";
    const data  = window["{data_var}"];

    function loadFullscreen(cb) {{
        if (typeof L !== 'undefined' && L.control && L.control.fullscreen) return cb();
        if (typeof L === 'undefined') return setTimeout(() => loadFullscreen(cb), 50);
        const s = document.createElement('script');
        s.src = 'https://unpkg.com/leaflet.fullscreen@3.0.2/Control.FullScreen.js';
        s.onload = cb;
        s.onerror = cb;
        document.head.appendChild(s);
    }}

    let attempts = 0;
    function init() {{
        const el = document.getElementById(mapId);
        if (!el || typeof L === 'undefined') return setTimeout(init, 50);
        if (el._leaflet_id) return;
        const hasFullscreen = !!(L.control && L.control.fullscreen);
        if (!hasFullscreen && attempts < 40) {{ attempts++; return setTimeout(init, 50); }}

        const osm = L.tileLayer(
            'https://{{s}}.tile.openstreetmap.org/{{z}}/{{x}}/{{y}}.png',
            {{ maxZoom: 19,
               attribution: '&copy; OpenStreetMap contributors' }}
        );

        const saintLayers = {{}};
        for (const s of data.saints) saintLayers[s.saint] = L.layerGroup();
        for (const m of data.markers) {{
            const popup =
                '<b>' + m.name + '</b><br>' +
                '<small>' + m.country + '</small><br>' +
                '<i>named after</i>: ' + m.saint + '<br>' +
                '<small><a href="https://www.wikidata.org/wiki/' +
                m.qid + '" target="_blank">Wikidata (' + m.qid + ')</a></small>';
            L.circleMarker([m.lat, m.lon], {{
                radius: 5, color: m.colour, weight: 1,
                fillColor: m.colour, fillOpacity: 0.8
            }}).bindPopup(popup, {{ maxWidth: 260 }})
              .addTo(saintLayers[m.saint]);
        }}

        const initial = [osm].concat(Object.values(saintLayers));
        const mapOpts = {{ center: data.centre, zoom: 6, layers: initial }};
        if (hasFullscreen) {{
